78	/// Scans MIR for `__cluster_config::<X, Y, Z>()` marker and extracts cluster dimensions.
79	///
80	/// The `#[cluster(x,y,z)]` macro injects this call at the start of the kernel.
81	/// We scan the MIR to find it and extract the const generic parameters.
82	///
83	/// Returns `Some(ClusterDims)` if found, `None` otherwise.
84	fn detect_cluster_config(body: &mir::Body) -> Option<ClusterDims> {
85	    use rustc_public::ty::TyConstKind;
86	
87	    for block in &body.blocks {
88	        // Use let-else for early continue pattern
89	        let mir::TerminatorKind::Call { func, .. } = &block.terminator.kind else {
90	            continue;
91	        };
92	        let mir::Operand::Constant(constant) = func else {
93	            continue;
94	        };
95	        let ConstantKind::ZeroSized = constant.const_.kind() else {
96	            continue;
97	        };
98	        let TyKind::RigidTy(RigidTy::FnDef(def_id, args)) = constant.const_.ty().kind() else {
99	            continue;
100	        };
101	
102	        let fn_name = def_id.name();
103	        if fn_name != "__cluster_config" && !fn_name.ends_with("::__cluster_config") {
104	            continue;
105	        }
106	
107	        // Extract const generic args (X, Y, Z)
108	        let mut dims = [1u32, 1u32, 1u32];
109	        for (i, arg) in args.0.iter().take(3).enumerate() {
110	            let rustc_public::ty::GenericArgKind::Const(c) = arg else {
111	                continue;
112	            };
113	            dims[i] = match c.kind() {
114	                TyConstKind::Value(_, alloc) => alloc.read_uint().ok().map(|v| v as u32),
115	                _ => c.eval_target_usize().ok().map(|v| v as u32),
116	            }
117	            .unwrap_or(dims[i]);
118	        }
119	
120	        return Some(ClusterDims {
121	            x: dims[0],
122	            y: dims[1],
123	            z: dims[2],
124	        });
125	    }
126	    None
127	}
