215	/// Return the non-unwind successors of a terminator.
216	///
217	/// [`mir::Terminator::successors`] includes unwind cleanup blocks alongside
218	/// "normal" control-flow targets. The CUDA toolchain does not support stack
219	/// unwinding (hardware could, but `nvcc`/`ptxas` never wire it up), so the
220	/// translator treats unwind cleanups as dead code. This helper strips them
221	/// out so the worklist only visits blocks that matter on GPU.
222	fn non_unwind_successors(kind: &mir::TerminatorKind) -> Vec<usize> {
223	    use mir::TerminatorKind::*;
224	    match kind {
225	        Goto { target } => vec![*target],
226	        SwitchInt { targets, .. } => targets.all_targets(),
227	        Return | Resume | Abort | Unreachable => vec![],
228	        Drop { target, .. } | Assert { target, .. } => vec![*target],
229	        Call { target, .. } => target.map(|t| vec![t]).unwrap_or_default(),
230	        InlineAsm { destination, .. } => destination.map(|t| vec![t]).unwrap_or_default(),
231	    }
232	}
233	
234	/// BFS from the entry block (index 0) following non-unwind successors.
235	///
236	/// The result is a sorted set of reachable-on-GPU block indices; unwind-only
237	/// cleanup blocks end up outside this set and are filled in with
238	/// `mir.unreachable` by [`translate_body`] so pliron verification still
239	/// passes.
240	fn compute_reachable_blocks(body: &mir::Body) -> std::collections::BTreeSet<usize> {
241	    let mut reachable = std::collections::BTreeSet::new();
242	    let mut frontier: Vec<usize> = vec![0];
243	    reachable.insert(0);
244	    while let Some(idx) = frontier.pop() {
245	        let successors = non_unwind_successors(&body.blocks[idx].terminator.kind);
246	        for succ in successors {
247	            if reachable.insert(succ) {
248	                frontier.push(succ);
249	            }
250	        }
251	    }
252	    reachable
253	}
