262	/// Build the first full-debug variable map.
263	///
264	/// This stage only supports simple whole-local bindings:
265	///
266	/// ```text
267	/// debug name => _3
268	/// ```
269	///
270	/// Fragments/projections need `DIExpression(DW_OP_LLVM_fragment, ...)` and more
271	/// value-location tracking, so they are intentionally skipped until the basic
272	/// local/argument path is solid.
273	fn collect_debug_locals(
274	    ctx: &mut Context,
275	    body: &mir::Body,
276	) -> FxHashMap<mir::Local, LocalDebugInfo> {
277	    let mut locals = FxHashMap::default();
278	
279	    for info in &body.var_debug_info {
280	        if info.composite.is_some() {
281	            continue;
282	        }
283	
284	        let Some(local) = info.local() else {
285	            continue;
286	        };
287	        let local_idx: usize = local;
288	        if local_idx == 0 {
289	            continue;
290	        }
291	
292	        let Some(decl) = body.local_decl(local) else {
293	            continue;
294	        };
295	        let Some(ty) = debug_type_for_ty(&decl.ty) else {
296	            continue;
297	        };
298	
299	        let name = info.name.to_string();
300	        if name.is_empty() {
301	            continue;
302	        }
303	
304	        locals.entry(local).or_insert_with(|| LocalDebugInfo {
305	            variable: DebugLocalVariableInfo {
306	                name,
307	                argument_index: info.argument_index,
308	                ty,
309	            },
310	            loc: span_to_location(ctx, info.source_info.span),
311	            source_scope: info.source_info.scope,
312	        });
313	    }
314	
315	    locals
316	}
