318	/// Maximum nesting depth for composite debug types. Guards against deeply
319	/// nested or (via generics) pathological value-type trees; beyond this we omit
320	/// the inner detail rather than recurse without bound.
321	const MAX_DEBUG_TYPE_DEPTH: usize = 8;
322	
323	fn debug_type_for_ty(ty: &Ty) -> Option<DebugLocalTypeKind> {
324	    debug_type_for_ty_at(ty, 0)
325	}
326	
327	fn debug_type_for_ty_at(ty: &Ty, depth: usize) -> Option<DebugLocalTypeKind> {
328	    match ty.kind() {
329	        TyKind::RigidTy(RigidTy::Bool) => Some(DebugLocalTypeKind::Basic {
330	            name: "bool".to_string(),
331	            size_bits: 8,
332	            encoding: "DW_ATE_boolean",
333	        }),
334	        TyKind::RigidTy(RigidTy::Int(int_ty)) => Some(DebugLocalTypeKind::Basic {
335	            name: int_name(int_ty).to_string(),
336	            size_bits: (int_ty.num_bytes() * 8) as u64,
337	            encoding: "DW_ATE_signed",
338	        }),
339	        TyKind::RigidTy(RigidTy::Uint(uint_ty)) => Some(DebugLocalTypeKind::Basic {
340	            name: uint_name(uint_ty).to_string(),
341	            size_bits: (uint_ty.num_bytes() * 8) as u64,
342	            encoding: "DW_ATE_unsigned",
343	        }),
344	        TyKind::RigidTy(RigidTy::Float(float_ty)) => Some(DebugLocalTypeKind::Basic {
345	            name: float_name(float_ty).to_string(),
346	            size_bits: float_size_bits(float_ty),
347	            encoding: "DW_ATE_float",
348	        }),
349	        TyKind::RigidTy(RigidTy::RawPtr(pointee, mutability)) => {
350	            Some(DebugLocalTypeKind::Pointer {
351	                name: raw_pointer_name(pointee, mutability),
352	                size_bits: 64,
353	            })
354	        }
355	        TyKind::RigidTy(RigidTy::Ref(_, pointee, mutability)) => {
356	            Some(DebugLocalTypeKind::Pointer {
357	                name: reference_name(pointee, mutability),
358	                size_bits: 64,
359	            })
360	        }
361	        TyKind::RigidTy(RigidTy::Tuple(subtypes)) if depth < MAX_DEBUG_TYPE_DEPTH => {
362	            let name = format!(
363	                "({})",
364	                subtypes
365	                    .iter()
366	                    .map(short_ty_name)
367	                    .collect::<Vec<_>>()
368	                    .join(", ")
369	            );
370	            let fields = subtypes
371	                .iter()
372	                .enumerate()
373	                .map(|(idx, sub)| (format!("__{idx}"), *sub));
374	            debug_struct_type(ty, name, fields, depth)
375	        }
376	        TyKind::RigidTy(RigidTy::Adt(adt_def, substs)) if depth < MAX_DEBUG_TYPE_DEPTH => {
377	            // Only plain structs (one variant) are described as composites here;
378	            // enums and unions need DWARF variant parts (deferred).
379	            if !matches!(adt_def.kind(), rustc_public::ty::AdtKind::Struct) {
380	                return None;
381	            }
382	            let variants = adt_def.variants();
383	            if variants.len() != 1 {
384	                return None;
385	            }
386	            let name = adt_def.trimmed_name();
387	            let fields = variants[0]
388	                .fields()
389	                .into_iter()
390	                .map(|field| (field.name.to_string(), field.ty_with_args(&substs)));
391	            debug_struct_type(ty, name, fields, depth)
392	        }
393	        TyKind::RigidTy(RigidTy::Array(elem_ty, len_const)) if depth < MAX_DEBUG_TYPE_DEPTH => {
394	            let count = array_len_const(&len_const)?;
395	            let element = debug_type_for_ty_at(&elem_ty, depth + 1)?;
396	            let size_bits = layout_size_bits(ty)?;
397	            Some(DebugLocalTypeKind::Array {
398	                name: format!("[{}; {count}]", short_ty_name(&elem_ty)),
399	                size_bits,
400	                element: Box::new(element),
401	                count,
402	            })
403	        }
404	        _ => None,
405	    }
406	}
