408	/// Build a `DICompositeType`-shaped struct/tuple from rustc's real layout.
409	///
410	/// Member offsets come from `ty.layout()` (so `repr(Rust)` field reordering is
411	/// honored), not declaration order. Fields whose type we cannot yet describe,
412	/// and zero-sized fields (e.g. `PhantomData`), are omitted; the remaining
413	/// members keep their correct offsets.
414	fn debug_struct_type(
415	    ty: &Ty,
416	    name: String,
417	    fields: impl Iterator<Item = (String, Ty)>,
418	    depth: usize,
419	) -> Option<DebugLocalTypeKind> {
420	    let layout = ty.layout().ok()?;
421	    let shape = layout.shape();
422	    let offsets: Vec<u64> = match &shape.fields {
423	        rustc_public::abi::FieldsShape::Arbitrary { offsets } => {
424	            offsets.iter().map(|off| off.bytes() as u64).collect()
425	        }
426	        _ => return None,
427	    };
428	    let size_bits = shape.size.bytes() as u64 * 8;
429	
430	    let mut members = Vec::new();
431	    for (idx, (field_name, field_ty)) in fields.enumerate() {
432	        let offset_bytes = *offsets.get(idx)?;
433	        let Some(member_ty) = debug_type_for_ty_at(&field_ty, depth + 1) else {
434	            continue;
435	        };
436	        if member_ty.size_bits() == 0 {
437	            continue;
438	        }
439	        members.push(DebugTypeMember {
440	            name: field_name,
441	            offset_bits: offset_bytes * 8,
442	            ty: member_ty,
443	        });
444	    }
445	
446	    if members.is_empty() {
447	        return None;
448	    }
449	
450	    Some(DebugLocalTypeKind::Struct {
451	        name,
452	        size_bits,
453	        members,
454	    })
455	}
