457	/// Total size of `ty` in bits from its layout, or `None` if unavailable.
458	fn layout_size_bits(ty: &Ty) -> Option<u64> {
459	    Some(ty.layout().ok()?.shape().size.bytes() as u64 * 8)
460	}
