462	/// Evaluate a fixed array's length constant to a `u64`.
463	fn array_len_const(len_const: &rustc_public::ty::TyConst) -> Option<u64> {
464	    match len_const.kind() {
465	        rustc_public::ty::TyConstKind::Value(_, alloc) => {
466	            let mut arr = [0u8; 8];
467	            for (i, byte) in alloc.bytes.iter().take(8).enumerate() {
468	                arr[i] = (*byte)?;
469	            }
470	            Some(u64::from_le_bytes(arr))
471	        }
472	        _ => None,
473	    }
474	}
