482	        TyKind::RigidTy(RigidTy::Float(float_ty)) => float_name(float_ty).to_string(),
483	        TyKind::RigidTy(RigidTy::RawPtr(..)) | TyKind::RigidTy(RigidTy::Ref(..)) => {
