557	/// Emit one `mir.alloca` per non-ZST MIR local at the top of the entry block,
558	/// then store each function argument into its backing slot.
559	///
560	/// This is the foundation of the alloca + load/store translator model: every
561	/// non-ZST MIR local is backed by a single stack slot recorded in `value_map`
562	/// via [`ValueMap::set_slot`]. Function arguments (which arrive as entry-block
563	/// arguments) are immediately stored into their slots so subsequent blocks can
564	/// load them without needing SSA block arguments.
565	///
566	/// `num_args` is the number of function arguments (MIR locals `1..=num_args`).
567	///
568	/// Returns the last operation emitted, so the caller can pass it to
569	/// [`block::translate_block`] as `entry_prev_op` to append block contents
570	/// **after** this setup (otherwise `insert_at_front` would push the alloca
571	/// chain past the block terminator).
572	///
573	/// # ZST locals
574	///
575	/// Locals whose Rust type is zero-sized (unit tuple, empty structs, `!`, …)
576	/// are skipped entirely: they get no slot in [`ValueMap`] and any attempted
577	/// load/store short-circuits.
578	///
579	/// # Unsupported types
580	///
581	/// [`types::translate_type`] can fail for locals whose types aren't supported
582	/// yet (e.g. ghost locals in kernels targeting unsupported surfaces). Those
583	/// locals simply get no slot; any later attempt to use them still errors out
584	/// through the existing unsupported-type code paths.
585	fn emit_entry_allocas(
586	    ctx: &mut Context,
587	    body: &mir::Body,
588	    entry_block: Ptr<BasicBlock>,
589	    num_args: usize,
590	    value_map: &mut ValueMap,
591	    debug_kind: DebugKind,
592	    debug_source_scopes: Option<&DebugSourceScopeMap>,
593	) -> Option<Ptr<Operation>> {
594	    let mut prev_op: Option<Ptr<Operation>> = None;
595	    let debug_locals = if debug_kind.variables_enabled() {
596	        collect_debug_locals(ctx, body)
597	    } else {
598	        FxHashMap::default()
599	    };
600	
601	    // Pre-scan the body once: for each local whose translated slot type is a
602	    // pointer, infer the address space from the *writes* into it rather than
603	    // trusting Rust's declared type (which loses addrspace info for
604	    // references / raw pointers).
605	    let slot_addr_spaces = SlotAddrSpaceMap::analyze(body);
606	
607	    for local_idx in 0..body.locals().len() {
608	        let local = mir::Local::from(local_idx);
609	        let local_ty = &body.locals()[local].ty;
610	        if types::is_rust_type_zst(local_ty) {
611	            continue;
612	        }
613	        let mir_ty = match types::translate_type(ctx, local_ty) {
614	            Ok(t) => t,
615	            Err(_) => continue,
616	        };
617	
618	        // Override the Rust-declared addrspace with the inferred one for
619	        // pointer slots. Non-pointer slots are untouched by
620	        // `align_pointer_addr_space`.
621	        let rust_declared =
622	            values::pointer_addr_space(ctx, mir_ty).unwrap_or(address_space::GENERIC);
623	        let target = slot_addr_spaces.effective(local, rust_declared);
624	        let mir_ty = values::align_pointer_addr_space(ctx, mir_ty, target);
625	
626	        let (op, slot) = ValueMap::emit_alloca(ctx, mir_ty, entry_block, prev_op);
627	        if let Some(info) = debug_locals.get(&local) {
628	            llvm_export::ops::set_debug_local_variable(ctx, op, info.variable.clone());
629	            if debug_source_scopes
630	                .is_some_and(|map| map.scopes.iter().any(|scope| scope.id == info.source_scope))
631	            {
632	                llvm_export::ops::set_debug_local_source_scope(ctx, op, info.source_scope);
633	            }
634	            op.deref_mut(ctx).set_loc(info.loc.clone());
635	        }
636	        prev_op = Some(op);
637	        value_map.set_slot(local, slot);
638	    }
639	
640	    for arg_idx in 0..num_args {
641	        let local = mir::Local::from(arg_idx + 1);
642	        let block_arg = entry_block.deref(ctx).get_argument(arg_idx);
643	        if let Some(op) = value_map.store_local(ctx, local, block_arg, entry_block, prev_op) {
644	            prev_op = Some(op);
645	        }
646	    }
647	
648	    prev_op
649	}
