651	/// Translates a MIR function body to a pliron IR `mir.func` operation.
652	///
653	/// # Process
654	///
655	/// 1. Extract signature (arg types from MIR locals 1..N, return from local 0)
656	/// 2. Create `mir.func` with signature and optional `gpu_kernel` attribute
657	/// 3. Create one pliron block per MIR block. The entry block carries the
658	///    function parameters; every other block is argument-less (cross-block
659	///    data flow travels through per-local alloca slots)
660	/// 4. Emit one `mir.alloca` per non-ZST local at the top of the entry block
661	///    and seed the argument slots from the block's parameters
662	/// 5. Translate every reachable block in index order
663	///
664	/// # Arguments
665	///
666	/// * `ctx` - Pliron IR context
667	/// * `body` - MIR function body
668	/// * `instance` - Monomorphized instance (with concrete generic args)
669	/// * `is_kernel` - Add `gpu_kernel` attribute for kernel entry points
670	/// * `is_inline_always` - Add `alwaysinline` attribute (non-kernel functions
671	///   marked `#[inline(always)]` in rustc)
672	/// * `override_name` - Custom export name (defaults to instance name)
673	pub fn translate_body(
674	    ctx: &mut Context,
675	    body: &mir::Body,
676	    instance: &mono::Instance,
677	    is_kernel: bool,
678	    is_inline_always: bool,
679	    override_name: Option<&str>,
680	    legaliser: &mut Legaliser,
681	    debug_kind: DebugKind,
682	    debug_source_scopes: Option<&DebugSourceScopeMap>,
683	) -> TranslationResult<Ptr<Operation>> {
684	    // Create a value map to track MIR locals -> pliron IR values
685	    let num_locals = body.locals().len();
686	    let mut value_map = ValueMap::new(num_locals);
687	
688	    // Get function argument types for the first block
689	    // In MIR, locals[0] is the return value, locals[1..arg_count+1] are function arguments
690	    let mut arg_types = Vec::new();
691	
692	    // Determine argument count from the function type in the instance
693	    // Get the function signature to determine the number of arguments
694	    let fn_ty = instance.ty();
695	    let num_args = match fn_ty.kind() {
696	        rustc_public::ty::TyKind::RigidTy(rustc_public::ty::RigidTy::FnDef(_, _)) => {
697	            // Get the function signature from fn_sig()
698	            let sig_binder = fn_ty.kind().fn_sig().unwrap();
699	            // Skip the binder to get the actual signature
700	            let sig = sig_binder.skip_binder();
701	            let inputs = sig.inputs();
702	            inputs.len()
703	        }
704	        rustc_public::ty::TyKind::RigidTy(rustc_public::ty::RigidTy::Closure(_, _)) => {
705	            // Closures use RustCall ABI where:
706	            // - MIR local 1 = self (closure environment, even if ZST)
707	            // - MIR locals 2..N = unpacked arguments from the fn_sig's tuple input
708	            //
709	            // fn_sig().inputs() returns just the tuple, NOT including self.
710	            // We need to count: 1 (self) + unpacked tuple elements
711	            let sig_binder = fn_ty.kind().fn_sig().unwrap();
712	            let sig = sig_binder.skip_binder();
713	            let inputs = sig.inputs();
714	
715	            // The input should be a single tuple (RustCall convention)
716	            let tuple_arg_count = if inputs.len() == 1 {
717	                // Get the tuple type and count its elements
718	                if let rustc_public::ty::TyKind::RigidTy(rustc_public::ty::RigidTy::Tuple(
719	                    tuple_tys,
720	                )) = inputs[0].kind()
721	                {
722	                    tuple_tys.len()
723	                } else {
724	                    // Not a tuple - use 1 (single arg)
725	                    1
726	                }
727	            } else {
728	                // Multiple inputs (shouldn't happen with RustCall, but handle it)
729	                inputs.len()
730	            };
731	
732	            // Total args = 1 (self) + unpacked tuple elements
733	            1 + tuple_arg_count
734	        }
735	        _ => {
736	            return input_err_noloc!(TranslationErr::unsupported(format!(
737	                "Expected FnDef or Closure type for function, got {:?}",
738	                fn_ty.kind()
739	            )));
740	        }
741	    };
742	
743	    for arg_idx in 0..num_args {
744	        // MIR local index for arguments: local 1, 2, 3, ... (0 is return value)
745	        let local = mir::Local::from(arg_idx + 1);
746	        let local_decl = &body.locals()[local];
747	        let ty = &local_decl.ty;
748	        let arg_type = types::translate_type(ctx, ty)?;
749	        arg_types.push(arg_type);
750	    }
751	
752	    // Get return type (local 0)
753	    let return_local = mir::Local::from(0usize);
754	    let return_decl = &body.locals()[return_local];
755	    let return_type_ptr = types::translate_type(ctx, &return_decl.ty)?;
756	
757	    // Unit-tuple returns become a void `mir.func` signature. We skip the
758	    // result so `MirReturnOp` isn't expected to carry an unused `()` operand
759	    // (`mir-lower` reconstructs the unit value at LLVM lowering time).
760	    let is_unit_return = {
761	        let return_type_obj = return_type_ptr.deref(ctx);
762	        if let Some(tuple_ty) = return_type_obj.downcast_ref::<dialect_mir::types::MirTupleType>() {
763	            tuple_ty.get_types().is_empty()
764	        } else {
765	            false
766	        }
767	    };
768	
769	    let return_types = if is_unit_return {
770	        vec![]
771	    } else {
772	        vec![return_type_ptr]
773	    };
774	
775	    // Create function type for signature
776	    use pliron::builtin::attributes::TypeAttr;
777	    use pliron::builtin::types::FunctionType;
778	    let func_type = FunctionType::get(
779	        ctx,
780	        arg_types.clone(), // inputs
781	        return_types,      // results
782	    );
783	    let func_type_attr = TypeAttr::new(func_type.into());
784	
785	    // Create a mir.func operation with a region for the function body
786	    let op_ptr = Operation::new(
787	        ctx,
788	        MirFuncOp::get_concrete_op_info(),
789	        vec![], // No result types
790	        vec![], // No operands
791	        vec![], // No successors
792	        1,      // 1 region for function body
793	    );
794	
795	    // Set the function location from rustc's body span. This becomes the
796	    // default scope line for line-table debug info once LLVM export is enabled.
797	    let loc = span_to_location(ctx, body.span);
798	    op_ptr.deref_mut(ctx).set_loc(loc);
799	
800	    // Create MirFuncOp and set the function type attribute and symbol name
801	    let mir_func_op = MirFuncOp::new(ctx, op_ptr, func_type_attr);
802	
803	    let name_str = if let Some(name) = override_name {
804	        name.to_string()
805	    } else {
806	        instance.name().to_string()
807	    };
808	    mir_func_op.set_symbol_name(ctx, legaliser.legalise(&name_str));
809	
810	    // Check if the function has the #[cuda_oxide::kernel] attribute (passed via is_kernel flag)
811	    if is_kernel {
812	        // Add "gpu_kernel" attribute to the mir.func operation.
813	        // This will be used by the lowering pass to set the "gpu_kernel" attribute on the llvm.func.
814	        use pliron::builtin::attributes::StringAttr;
815	        let kernel_attr = StringAttr::new("true".to_string());
816	        let key: Identifier = "gpu_kernel".try_into().unwrap();
817	        mir_func_op
818	            .get_operation()
819	            .deref_mut(ctx)
820	            .attributes
821	            .set(key, kernel_attr);
822	
823	        // Detect compile-time cluster configuration from #[cluster(x,y,z)] attribute
824	        if let Some(cluster_dims) = detect_cluster_config(body) {
825	            use pliron::builtin::attributes::IntegerAttr;
826	            use pliron::builtin::types::Signedness;
827	            use pliron::utils::apint::APInt;
828	            use std::num::NonZero;
829	
830	            // Add cluster_dim_x/y/z attributes
831	            // These will be used by the LLVM export to emit nvvm.annotations metadata
832	            let u32_ty = pliron::builtin::types::IntegerType::get(ctx, 32, Signedness::Unsigned);
833	            let width = NonZero::new(32).unwrap();
834	
835	            // Create APInt values for each dimension
836	            let apint_x = APInt::from_u32(cluster_dims.x, width);
837	            let apint_y = APInt::from_u32(cluster_dims.y, width);
838	            let apint_z = APInt::from_u32(cluster_dims.z, width);
839	
840	            let x_attr = IntegerAttr::new(u32_ty, apint_x);
841	            let y_attr = IntegerAttr::new(u32_ty, apint_y);
842	            let z_attr = IntegerAttr::new(u32_ty, apint_z);
843	
844	            let x_key: Identifier = "cluster_dim_x".try_into().unwrap();
845	            let y_key: Identifier = "cluster_dim_y".try_into().unwrap();
846	            let z_key: Identifier = "cluster_dim_z".try_into().unwrap();
847	
848	            let mut op_mut = mir_func_op.get_operation().deref_mut(ctx);
849	            op_mut.attributes.set(x_key, x_attr);
850	            op_mut.attributes.set(y_key, y_attr);
851	            op_mut.attributes.set(z_key, z_attr);
852	
853	            if std::env::var("CUDA_OXIDE_VERBOSE").is_ok() {
854	                eprintln!(
855	                    "  Cluster config detected: {}x{}x{}",
856	                    cluster_dims.x, cluster_dims.y, cluster_dims.z
857	                );
858	            }
859	        }
860	
861	        // Detect compile-time launch bounds from #[launch_bounds(max, min)] attribute
862	        if let Some(launch_bounds) = detect_launch_bounds_config(body) {
863	            use pliron::builtin::attributes::IntegerAttr;
864	            use pliron::builtin::types::Signedness;
865	            use pliron::utils::apint::APInt;
866	            use std::num::NonZero;
867	
868	            // Add maxntid and minctasm attributes
869	            // These will be used by the LLVM export to emit nvvm.annotations metadata
870	            let u32_ty = pliron::builtin::types::IntegerType::get(ctx, 32, Signedness::Unsigned);
871	            let width = NonZero::new(32).unwrap();
872	
873	            // Create APInt values
874	            let apint_max = APInt::from_u32(launch_bounds.max_threads, width);
875	            let max_attr = IntegerAttr::new(u32_ty, apint_max);
876	            let max_key: Identifier = "maxntid".try_into().unwrap();
877	
878	            let mut op_mut = mir_func_op.get_operation().deref_mut(ctx);
879	            op_mut.attributes.set(max_key, max_attr);
880	
881	            // Only add minctasm if it's non-zero (specified)
882	            if launch_bounds.min_blocks > 0 {
883	                let apint_min = APInt::from_u32(launch_bounds.min_blocks, width);
884	                let min_attr = IntegerAttr::new(u32_ty, apint_min);
885	                let min_key: Identifier = "minctasm".try_into().unwrap();
886	                op_mut.attributes.set(min_key, min_attr);
887	            }
888	
889	            if std::env::var("CUDA_OXIDE_VERBOSE").is_ok() {
890	                if launch_bounds.min_blocks > 0 {
891	                    eprintln!(
892	                        "  Launch bounds detected: maxntid={}, minctasm={}",
893	                        launch_bounds.max_threads, launch_bounds.min_blocks
894	                    );
895	                } else {
896	                    eprintln!(
897	                        "  Launch bounds detected: maxntid={}",
898	                        launch_bounds.max_threads
899	                    );
900	                }
901	            }
902	        }
903	    }
904	
905	    // Attribute macros may run before `#[kernel]`. Generic expansion forwards
906	    // that marker to the entry but also keeps the original in its helper, so
907	    // record markers on any function. mir-lower treats every marked local
908	    // function as a propagation root and carries the minimum to its callees.
909	    if let Some(alignment) = detect_dynamic_shared_alignment(body) {
910	        use pliron::builtin::attributes::IntegerAttr;
911	        use pliron::builtin::types::Signedness;
912	        use pliron::utils::apint::APInt;
913	        use std::num::NonZero;
914	
915	        let u64_ty = pliron::builtin::types::IntegerType::get(ctx, 64, Signedness::Unsigned);
916	        let value = APInt::from_u64(alignment.bytes, NonZero::new(64).unwrap());
917	        let key: Identifier = "dynamic_shared_alignment".try_into().unwrap();
918	        mir_func_op
919	            .get_operation()
920	            .deref_mut(ctx)
921	            .attributes
922	            .set(key, IntegerAttr::new(u64_ty, value));
923	
924	        if std::env::var("CUDA_OXIDE_VERBOSE").is_ok() {
925	            eprintln!(
926	                "  Dynamic shared-memory contract alignment detected: {}",
927	                alignment.bytes
928	            );
929	        }
930	    }
931	
932	    if let Some(scope_map) = debug_source_scopes
933	        && debug_kind.variables_enabled()
934	    {
935	        llvm_export::ops::set_debug_source_scope_map(ctx, op_ptr, scope_map);
936	    }
937	
938	    set_alwaysinline_attr_from_flag(ctx, &mir_func_op, is_kernel, is_inline_always);
939	
940	    // Get the function body region (region 0)
941	    let region_ptr = op_ptr.deref(ctx).get_region(0);
942	
943	    // -------------------------------------------------------------------------
944	    // PHASE 1: Create all pliron IR blocks
945	    // -------------------------------------------------------------------------
946	    //
947	    // Only the entry block receives block arguments (the function's formal
948	    // parameters). Every other block is argument-less: cross-block data flow
949	    // travels through the per-local alloca slots, not block arguments.
950	    let mut block_map: Vec<Ptr<BasicBlock>> = Vec::new();
951	
952	    for (idx, _mir_block) in body.blocks.iter().enumerate() {
953	        let arg_types_for_block = if idx == 0 { arg_types.clone() } else { vec![] };
954	
955	        let block_ptr = BasicBlock::new(ctx, None, arg_types_for_block);
956	        block_map.push(block_ptr);
957	    }
958	
959	    // Link all blocks into the function's region.
960	    for (idx, block_ptr) in block_map.iter().enumerate() {
961	        if idx == 0 {
962	            block_ptr.insert_at_front(region_ptr, ctx);
963	        } else {
964	            block_ptr.insert_after(ctx, block_map[idx - 1]);
965	        }
966	    }
967	
968	    // -------------------------------------------------------------------------
969	    // PHASE 1.5: Entry-block allocas + argument stores
970	    // -------------------------------------------------------------------------
971	    //
972	    // Every non-ZST MIR local is backed by a single stack slot emitted at the
973	    // top of the entry block; its pointer is recorded in `value_map` via
974	    // `set_slot`. Function arguments are eagerly stored into their slots so
975	    // later blocks can `load_local` them without needing block arguments.
976	    //
977	    // The `mem2reg` pass in `pipeline.rs` promotes the scalar slots back into
978	    // SSA before LLVM lowering.
979	    let entry_last_op = emit_entry_allocas(
980	        ctx,
981	        body,
982	        block_map[0],
983	        num_args,
984	        &mut value_map,
985	        debug_kind,
986	        debug_source_scopes,
987	    );
988	
989	    // -------------------------------------------------------------------------
990	    // PHASE 2: Translate reachable blocks
991	    // -------------------------------------------------------------------------
992	    //
993	    // Every local flows through its stack slot, so blocks have no inter-block
994	    // ordering dependency and can be translated in a single index-order pass.
995	    // Unwind-only cleanup blocks are skipped here (see
996	    // [`non_unwind_successors`]) and patched with `mir.unreachable` below.
997	    let reachable: std::collections::BTreeSet<usize> = compute_reachable_blocks(body);
998	
999	    let mut blocks_processed: std::collections::HashSet<usize> = std::collections::HashSet::new();
1000	
1001	    for idx in reachable.iter().copied() {
1002	        let mir_block = &body.blocks[idx];
1003	        let block_ptr = block_map[idx];
1004	        let entry_prev_op = if idx == 0 { entry_last_op } else { None };
1005	        block::translate_block(
1006	            ctx,
1007	            body,
1008	            mir_block,
1009	            idx,
1010	            block_ptr,
1011	            &mut value_map,
1012	            &block_map,
1013	            legaliser,
1014	            entry_prev_op,
1015	        )?;
1016	        blocks_processed.insert(idx);
1017	    }
1018	
1019	    // Unwind cleanup blocks are unreachable on GPU but pliron still requires
1020	    // every block to have a terminator, so we stitch `mir.unreachable` onto
1021	    // the ones we skipped above. Later passes are free to drop them as dead
1022	    // code.
1023	    for (idx, &block_ptr) in block_map.iter().enumerate().take(body.blocks.len()) {
1024	        if !blocks_processed.contains(&idx) {
1025	            let unreachable_op = Operation::new(
1026	                ctx,
1027	                dialect_mir::ops::MirUnreachableOp::get_concrete_op_info(),
1028	                vec![],
1029	                vec![],
1030	                vec![],
1031	                0,
1032	            );
1033	            unreachable_op.insert_at_front(block_ptr, ctx);
1034	        }
1035	    }
1036	
1037	    Ok(op_ptr)
1038	}
