1040	/// Propagate `#[inline(always)]` as an LLVM `alwaysinline` function
1041	/// attribute. Kernel entry points are excluded because they're `.entry` in PTX
1042	/// and never callees, so marking them `alwaysinline` would be a no-op at best
1043	/// and rejected by LLVM at worst.
1044	fn set_alwaysinline_attr_from_flag(
1045	    ctx: &mut Context,
1046	    mir_func_op: &MirFuncOp,
1047	    is_kernel: bool,
1048	    is_inline_always: bool,
1049	) {
1050	    if is_inline_always && !is_kernel {
1051	        let attr = pliron::builtin::attributes::StringAttr::new("true".to_string());
1052	        let key: Identifier = "alwaysinline".try_into().unwrap();
1053	        mir_func_op
1054	            .get_operation()
1055	            .deref_mut(ctx)
1056	            .attributes
1057	            .set(key, attr);
1058	    }
1059	}
